module.render:
const esc = (s) => String(s).replace(/&/g,'&amp;').replace(/</g,'&lt;').replace(/>/g,'&gt;');
// Classify a Big-O string into a 0..5 severity for colouring.
const rank = (o) => {
  const s = o.replace(/\s+/g, '').toLowerCase();
  if (/o\(1\)/.test(s)) return 0;
  if (/log/.test(s) && !/n\^?\d|n!|\^n/.test(s)) return 1;
  if (/o\(n\)$|o\(n\)/.test(s) && !/log|n\^|n!|\^n/.test(s)) return 2;
  if (/nlog|n\\?log/.test(s)) return 3;
  if (/n\^?2|n\^?3|n\^\{?\d/.test(s)) return 4;
  if (/\^n|n!|2\^|factorial/.test(s)) return 5;
  return 2;
};
const colors = ['#16a34a', '#0891b2', '#2563eb', '#ca8a04', '#ea580c', '#dc2626'];
const rows = [];
sections.forEach((sec) => {
  const idx = String(sec || '').indexOf('|');
  if (idx < 0) return;
  rows.push({ name: sec.slice(0, idx).trim(), o: sec.slice(idx + 1).trim() });
});
let html = `\n\n<div class="mdp-mod-bigo">`;
if (args.label) html += `<div class="mdp-bo-row mdp-bo-head"><span class="mdp-bo-name"></span><span class="mdp-bo-val">${esc(args.label)}</span></div>`;
rows.forEach((r) => {
  const c = colors[rank(r.o)];
  html += `<div class="mdp-bo-row"><span class="mdp-bo-name">${esc(r.name)}</span>` +
    `<span class="mdp-bo-pill" style="--bo-c:${c};">\n\n\\(${r.o}\\)\n\n</span></div>`;
});
html += `</div>\n\n`;
return html;
